    std::uint64_t aOrbiterE = 0; std::uint64_t aOrbiterF = 0; std::uint64_t aOrbiterG = 0; std::uint64_t aOrbiterH = 0;
    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseC(pNonce * 0xC44AD9FFE2502153ULL + 0xD798D98AFE87770DULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseB(pNonce * 0xDD97A69EC1307595ULL + 0x97C290758C2BED89ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseC(pNonce * 0xA2F7889F7D1EF179ULL + 0xB3B6992AB3276887ULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseB(pNonce * 0xEFE7BB41F2A12AE9ULL + 0xC4116901A53CE515ULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseA(pNonce * 0xFC35BF13ED7CF3DDULL + 0xBF9565D033F7D081ULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0x9C014F867A377AB9ULL + 0xB4A8BD6BE4679C17ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0x940A304BB6319F9DULL + 0xCA14101691480433ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xE1FA2B3CDBFCABA5ULL + 0xA84C01F732632505ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0x8FB88F4B59EE3C95ULL + 0x8250CC5AE4D7D8C0ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xCB74F9269DDA997BULL + 0xC858189C5FE37E6BULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0xD8EF22CC286F19A3ULL + 0xB597F70CFB18FCD2ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0xB88588CC29049AF3ULL + 0xE2D69C814CB271C0ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseA(pNonce * 0x8DC71CE9EE35A15BULL + 0x9FED43365A8852A6ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xCD399264859C478BULL + 0xE7BF37DF0FD2EA2AULL);
