    std::uint64_t aNonceWordP = TwistMix64::DiffuseC(pNonce * 0xB836DACF3BB0622BULL + 0xA9B48ED08DFDF89FULL);
    std::uint64_t aDomainWordIngress = pConstants->mIngress;
