            aCross = RotL64(pSnow[((S_BLOCK1 - aIndex + 3997U)) & S_BLOCK1], 22U) ^ RotL64(aSource[((S_BLOCK1 - aIndex + 5395U)) & S_BLOCK1], 3U);
