            aOrbiterD = (((aWandererG + RotL64(aPrevious, 13U)) + 4656103762822508758U) + aOrbiterAssignSaltF[(((31U - aIndex) + 9U)) & S_SALT1]) + aNonceWordK;
            aOrbiterK = ((aWandererD + RotL64(aIngress, 54U)) + 15114585866908528766U) + aNonceWordA;
            aOrbiterB = (aWandererJ + RotL64(aScatter, 23U)) + 2761039078527315255U;
            aOrbiterJ = ((aWandererB + RotL64(aCross, 11U)) + RotL64(aCarry, 35U)) + 16970882194415647916U;
            aOrbiterG = ((aWandererA + RotL64(aScatter, 47U)) + 6259110916963159204U) + aOrbiterAssignSaltA[((aIndex + 20U)) & S_SALT1];
