            //
            aOrbiterI = ((aOrbiterI + aOrbiterA) + 14289887902759316946U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 4566605402410444115U;
            aOrbiterD = RotL64((aOrbiterD * 2077145435788955457U), 57U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 7278210121337616789U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterK) ^ 15742210554557022130U) ^ aOrbiterUpdateSaltD[((aIndex + 8U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 7688603762738710789U), 13U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 3996130065459089431U;
            aOrbiterG = (aOrbiterG ^ aOrbiterD) ^ 12815686280397614958U;
            aOrbiterG = RotL64((aOrbiterG * 1892575397103447193U), 37U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterD) + 1475841441402733081U;
            aOrbiterE = ((aOrbiterE ^ aOrbiterC) ^ 17131604740961123658U) ^ aOrbiterUpdateSaltE[((aIndex + 21U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 8715575657456921163U), 19U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 14513708006438300876U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterE) ^ 14940001659479467231U) ^ aNonceWordH;
            aOrbiterI = RotL64((aOrbiterI * 4007530533960110369U), 11U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterB) + 17862462156261721223U) + aNonceWordN;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterA) ^ 17458986642864077053U;
            aOrbiterJ = RotL64((aOrbiterJ * 11689637242840053243U), 53U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 17110996579736768266U;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 8139721287392733150U;
            aOrbiterH = RotL64((aOrbiterH * 11417386628808789923U), 35U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterF) + 5112799688078434440U;
            aOrbiterK = (aOrbiterK ^ aOrbiterJ) ^ 11355673285903173060U;
            aOrbiterK = RotL64((aOrbiterK * 12322991021882431249U), 23U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterK) + 16000442529575121120U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterG) ^ 3360065887482808106U) ^ aNonceWordG;
            aOrbiterA = RotL64((aOrbiterA * 10003830991298470837U), 5U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterC) + 11402684335849702064U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 12U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterB) ^ 4349117675794365051U;
            aOrbiterF = RotL64((aOrbiterF * 11101144591568141239U), 47U);
            //
            aIngress = aOrbiterH ^ RotL64(aOrbiterJ, 23U);
            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterI, 47U));
            aIngress = aIngress + (RotL64(aOrbiterD, 53U) ^ aOrbiterC);
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterK, 37U));
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterA, 29U));
